    controller->last_level = 0;
    controller->last_valid_sensor_ms = 0U;
    controller->first_sensor_reading_done = false;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .pump_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_pump_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_pump_on = controller->pump_on;
    previous_state = controller->state;

    /* Task-specific control policy:
     * - turn pump ON when LEVEL < 30
     * - turn pump OFF when LEVEL > 80
     * - hold previous safe output while 30 <= LEVEL <= 80
     * - fail safe to PUMP OFF on malformed input or timeout
     */
    switch (input.kind) {
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_sensor = true;
        controller->last_level = input.level;
        controller->last_valid_sensor_ms = input.now_ms;

        if (controller->has_valid_sensor && controller->last_valid_sensor_ms > 0) {
            /* Check for sensor timeout - only check after first valid reading */
            uint32_t elapsed_ms = input.now_ms - controller->last_valid_sensor_ms;

            if (!controller->first_sensor_reading_done) {
                /* First valid reading: mark that we've done the initial check, 
                   but still apply control policy */
                controller->first_sensor_reading_done = true;
            } else if (elapsed_ms >= CONTROLLER_SENSOR_TIMEOUT_MS) {
                /* Timeout detected - lose sensor data and fail safe */
                controller->has_valid_sensor = false;
                controller->last_level = 0;
                controller_set_safe_off(controller);
            }

            // Always apply control policy when we have valid sensor data (unless timed out)
            if (!controller->first_sensor_reading_done || elapsed_ms < CONTROLLER_SENSOR_TIMEOUT_MS) {
                /* Apply control policy based on level */
                if (input.level < CONTROLLER_LEVEL_LOW_THRESHOLD) {
